/*
 * forge_controller.ino — Induction Forge Temperature Controller
 *
 * Elements:
 *   1. MAX31865 PT100 RTD   — SPI, forge temp at 10 Hz
 *   2. N-MOSFET             — D5, 10 Hz PWM → induction driver WORK_EN
 *   3. Rotary Encoder       — setpoint ±10 °C per detent, long-press on/off
 *   4. SSD1306 OLED         — setpoint / actual / power / status
 *   5. Arduino Nano         — PID + safety cutoff
 */

#include <Wire.h>
#include <SPI.h>
#include <Adafruit_MAX31865.h>
#include <Adafruit_SSD1306.h>

// --- Pins ---
#define RTD_CS     10
#define HEAT_PWM    5
#define RELAY_PIN   8   // safety cutoff relay (NC contact)
#define BUZZ_PIN    9
#define ENC_CLK     2
#define ENC_DT      4
#define ENC_SW      3

// --- Safety ---
#define CUTOFF_C   1250.0f

// --- PID (conservative for large thermal mass) ---
#define KP  0.3f
#define KI  0.02f
#define KD  5.0f
#define PERIOD_MS 100UL
#define WINDOW_MS 100UL

// --- Objects ---
Adafruit_MAX31865 rtd(RTD_CS);
Adafruit_SSD1306  oled(128, 64, &Wire, -1);

// --- State ---
float setpoint  = 800.0f;
float actual    = 20.0f;
float i_term    = 0.0f;
float prev_err  = 0.0f;
float output    = 0.0f;
bool  active    = false;
bool  cutoff    = false;

volatile int  enc_d  = 0;
volatile bool enc_p  = false;
volatile bool enc_lp = false;
unsigned long press_start = 0;

void ICACHE_RAM_ATTR isr_clk() { enc_d += digitalRead(ENC_DT) ? -1 : 1; }
void ICACHE_RAM_ATTR isr_sw()  {
  if (digitalRead(ENC_SW) == LOW) press_start = millis();
  else {
    if (millis() - press_start > 1000) enc_lp = true;
    else enc_p = true;
  }
}

float median5(float* a) {
  for (int i = 0; i < 4; i++)
    for (int j = i+1; j < 5; j++)
      if (a[i] > a[j]) { float t=a[i]; a[i]=a[j]; a[j]=t; }
  return a[2];
}

float run_pid(float sp, float pv, float dt) {
  float e = sp - pv;
  i_term   = constrain(i_term + KI * e * dt, 0.0f, 100.0f);
  float d  = (e - prev_err) / dt;
  prev_err = e;
  return constrain(KP * e + i_term + KD * d, 0.0f, 100.0f);
}

void trigger_cutoff() {
  cutoff = true; active = false;
  analogWrite(HEAT_PWM, 0);
  digitalWrite(RELAY_PIN, LOW);  // open NC relay = cuts heater power
  for (int i = 0; i < 10; i++) {
    digitalWrite(BUZZ_PIN, HIGH); delay(100);
    digitalWrite(BUZZ_PIN, LOW);  delay(100);
  }
  Serial.printf("CUTOFF at %.0f C\n", actual);
}

void update_oled(const char* status) {
  oled.clearDisplay();
  oled.setTextSize(2); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0, 0); oled.printf("%4.0f C", setpoint);
  oled.setTextSize(1);
  oled.setCursor(0, 20); oled.printf("Actual: %5.1f C", actual);
  oled.setCursor(0, 32); oled.printf("Power:  %5.1f %%", output);
  oled.setCursor(0, 44);
  if (cutoff) {
    oled.fillRect(0, 42, 128, 12, SSD1306_WHITE);
    oled.setTextColor(SSD1306_BLACK);
    oled.setCursor(2, 44); oled.print("!! CUTOFF !!");
    oled.setTextColor(SSD1306_WHITE);
  } else {
    oled.print(status);
  }
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin(); SPI.begin();
  rtd.begin(MAX31865_2WIRE);
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  pinMode(HEAT_PWM, OUTPUT); analogWrite(HEAT_PWM, 0);
  pinMode(RELAY_PIN, OUTPUT); digitalWrite(RELAY_PIN, HIGH); // NC relay closed = power available
  pinMode(BUZZ_PIN, OUTPUT); digitalWrite(BUZZ_PIN, LOW);
  pinMode(ENC_CLK, INPUT_PULLUP); pinMode(ENC_DT, INPUT_PULLUP); pinMode(ENC_SW, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_CLK), isr_clk, FALLING);
  attachInterrupt(digitalPinToInterrupt(ENC_SW),  isr_sw,  CHANGE);

  Serial.println(F("Forge controller ready."));
}

void loop() {
  static unsigned long last_pid  = 0;
  static unsigned long win_start = 0;

  unsigned long now = millis();

  // --- Encoder ---
  noInterrupts(); int d = enc_d; enc_d = 0; bool p = enc_p; enc_p = false; bool lp = enc_lp; enc_lp = false; interrupts();
  if (d != 0 && !cutoff) setpoint = constrain(setpoint + d * 10.0f, 200.0f, 1200.0f);
  if (lp && !cutoff) { active = !active; if (!active) { output = 0; analogWrite(HEAT_PWM, 0); } }

  // --- PID at 10 Hz ---
  if (now - last_pid >= PERIOD_MS) {
    float dt = (now - last_pid) / 1000.0f;
    last_pid = now;

    // Median-5 filter
    float s[5];
    for (int i = 0; i < 5; i++) s[i] = rtd.temperature(100.0f, 430.0f);
    actual = median5(s);

    if (actual >= CUTOFF_C && !cutoff) trigger_cutoff();

    if (active && !cutoff) {
      output = run_pid(setpoint, actual, dt);
    } else {
      output = 0.0f;
    }

    const char* status = !active ? "STANDBY" :
                          actual < setpoint - 30.0f ? "HEATING" : "AT TEMP";
    update_oled(status);
    Serial.printf("T=%.1f SP=%.0f OUT=%.0f %s\n", actual, setpoint, output, status);
  }

  // --- PWM window ---
  if (!cutoff && active) {
    if (now - win_start >= WINDOW_MS) win_start = now;
    bool on = (now - win_start) < (unsigned long)(output * WINDOW_MS / 100.0f);
    analogWrite(HEAT_PWM, on ? 255 : 0);
  } else {
    analogWrite(HEAT_PWM, 0);
  }
}
